import requests

urls = ['http://localhost:80/dev1.jpeg', 'http://localhost:80/dev2.jpeg']
for url in urls:
    data = requests.get(url, timeout=10).content
    print(url, 'size', len(data))
    for marker in [b'FLAG{', b'CTF{', b'flag{', b'FAKE{', b'FLG{']:
        idx = data.find(marker)
        if idx != -1:
            end = data.find(b'}', idx)
            print('Found marker', marker, '->', data[idx:end+1])
